const config = $('Normalize Token Set').first().json;
const path = '/api/v2/order/get_order_list';
const timestamp = Math.floor(Date.now() / 1000);
const lookbackDays = Number(config.lookbackDays || '3');
const timeTo = timestamp;
const timeFrom = timestamp - lookbackDays * 24 * 60 * 60;
const baseString = `${config.partnerId}${path}${timestamp}${config.accessToken}${config.shopId}`;
const sign = hmacSha256(config.partnerKey, baseString);
const requestUrl = `${config.shopeeApiBase}${path}?partner_id=${encodeURIComponent(config.partnerId)}&timestamp=${timestamp}&access_token=${encodeURIComponent(config.accessToken)}&shop_id=${encodeURIComponent(config.shopId)}&sign=${sign}&time_range_field=update_time&time_from=${timeFrom}&time_to=${timeTo}&page_size=50`;

return [
  {
    json: {
      ...config,
      path,
      timestamp,
      timeFrom,
      timeTo,
      sign,
      requestUrl
    }
  }
];

const input = $input.first().json;
const orderList = input.response?.order_list ?? [];

if (!Array.isArray(orderList) || orderList.length === 0) {
  return [];
}

return orderList.map((order) => {
  const body = {
    store_id: input.storeId,
    platform_order_id: order.order_sn,
    barcode_value: order.order_sn,
    buyer_name: order.buyer_username ?? null,
    items_json: [],
    awb_status: 'pending'
  };

  return {
    json: {
      ...body,
      supabaseUrl: input.supabaseUrl,
      serviceRoleKey: input.serviceRoleKey,
      requestUrl: `${input.supabaseUrl}/rest/v1/orders?on_conflict=store_id,platform_order_id`,
      requestBody: JSON.stringify(body)
    }
  };
});
